Definition wolframToShefferFinal : list E :=
  match Certificate.runItems wolframInitial wolframToShefferItems with
  | Some eqs => eqs
  | None => []
end.

Theorem wolframToShefferRun :
    Certificate.runItems wolframInitial wolframToShefferItems = Some wolframToShefferFinal.
Proof. vm_compute. reflexivity. Qed.

Theorem wolframToShefferKnown1 :
    Certificate.known wolframToShefferFinal shefferEquation1 = true.
Proof. vm_compute. reflexivity. Qed.

Theorem wolframToShefferKnown2 :
    Certificate.known wolframToShefferFinal shefferEquation2 = true.
Proof. vm_compute. reflexivity. Qed.

Theorem wolframToShefferKnown3 :
    Certificate.known wolframToShefferFinal shefferEquation3 = true.
Proof. vm_compute. reflexivity. Qed.

Theorem wolframToSheffer_valid {A : Type} (op : A -> A -> A)
    (hW : Equation.Valid op wolframEquation) :
    Equation.Valid op shefferEquation1 /\
      Equation.Valid op shefferEquation2 /\ Equation.Valid op shefferEquation3.
Proof.
  pose proof (Certificate.runItems_sound (op := op) wolframToShefferRun) as hsound.
  assert (hinitial : AllValid op wolframInitial).
  { intros eq he. simpl in he. destruct he as [<- | []]. exact hW. }
  pose proof (hsound hinitial) as hall.
  split.
  - exact (Certificate.known_sound wolframToShefferKnown1 hall).
  - split.
    + exact (Certificate.known_sound wolframToShefferKnown2 hall).
    + exact (Certificate.known_sound wolframToShefferKnown3 hall).
Qed.

Definition meredithToWolframFinal : list E :=
  match Certificate.runItems meredithInitial meredithToWolframItems with
  | Some eqs => eqs
  | None => []
end.

Theorem meredithToWolframRun :
    Certificate.runItems meredithInitial meredithToWolframItems = Some meredithToWolframFinal.
Proof. vm_compute. reflexivity. Qed.

Theorem meredithToWolframKnown :
    Certificate.known meredithToWolframFinal wolframEquation = true.
Proof. vm_compute. reflexivity. Qed.

Theorem meredithToWolfram_valid {A : Type} (op : A -> A -> A)
    (hM1 : Equation.Valid op meredithEquation1)
    (hM2 : Equation.Valid op meredithEquation2) :
    Equation.Valid op wolframEquation.
Proof.
  pose proof (Certificate.runItems_sound (op := op) meredithToWolframRun) as hsound.
  assert (hinitial : AllValid op meredithInitial).
  { intros eq he. simpl in he. destruct he as [<- | [<- | []]].
    - exact hM1.
    - exact hM2. }
  pose proof (hsound hinitial) as hall.
  exact (Certificate.known_sound meredithToWolframKnown hall).
Qed.

